const express = require('express');

const app = express();
app.use(express.json({ limit: '256kb' }));

const PORT = process.env.PORT || 3000;

// -------------------- In-memory "DB" --------------------
const db = {
  users: new Map(), // userId -> { userId, createdAt, completedLevels: Map(levelId -> completion), wallet: { coins, gems }, pendingRewards: Map(rewardId -> reward), claimedRewards: Set(rewardId) }
};

function nowIso() {
  return new Date().toISOString();
}

function getOrCreateUser(userId) {
  if (!userId || typeof userId !== 'string') return null;
  let u = db.users.get(userId);
  if (!u) {
    u = {
      userId,
      createdAt: nowIso(),
      completedLevels: new Map(),
      wallet: { coins: 0, gems: 0 },
      pendingRewards: new Map(),
      claimedRewards: new Set()
    };
    db.users.set(userId, u);
  }
  return u;
}

function parseIntSafe(v) {
  const n = Number(v);
  if (!Number.isFinite(n)) return null;
  return Math.trunc(n);
}

function parseFloatSafe(v) {
  const n = Number(v);
  if (!Number.isFinite(n)) return null;
  return n;
}

function clamp(n, min, max) {
  return Math.max(min, Math.min(max, n));
}

function makeId(prefix = 'rwd') {
  return `${prefix}_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 10)}`;
}

// -------------------- Reward logic --------------------
// Note: Rewards are awarded based on client-reported metrics (score/time).
function computeRewards({ levelId, score, timeMs, isFirstClear }) {
  // Basic, simple casual puzzle tuning.
  // Score: higher is better. Time: lower is better.
  const baseCoins = 25;
  const firstClearBonus = isFirstClear ? 50 : 0;

  // Score tiers
  let scoreCoins = 0;
  if (score >= 3000) scoreCoins = 120;
  else if (score >= 2000) scoreCoins = 80;
  else if (score >= 1000) scoreCoins = 45;
  else if (score >= 500) scoreCoins = 25;
  else scoreCoins = 10;

  // Time bonus tiers (ms)
  let timeCoins = 0;
  if (timeMs <= 30_000) timeCoins = 80;
  else if (timeMs <= 60_000) timeCoins = 45;
  else if (timeMs <= 120_000) timeCoins = 20;
  else timeCoins = 0;

  let gems = 0;
  if (score >= 3000 && timeMs <= 60_000) gems += 2;
  else if (score >= 2000 && timeMs <= 90_000) gems += 1;

  // Small per-level variability (deterministic) to avoid uniformity.
  const levelHash = (() => {
    let h = 0;
    const s = String(levelId);
    for (let i = 0; i < s.length; i++) h = (h * 31 + s.charCodeAt(i)) >>> 0;
    return h;
  })();
  const levelBonus = (levelHash % 11); // 0..10

  let coins = baseCoins + scoreCoins + timeCoins + firstClearBonus + levelBonus;

  // Hard caps (simple)
  coins = clamp(coins, 0, 500);
  gems = clamp(gems, 0, 10);

  return { coins, gems };
}

function validateCompletionPayload(body) {
  const userId = body?.userId;
  const levelId = body?.levelId;

  const score = parseIntSafe(body?.score);
  const timeMs = parseIntSafe(body?.timeMs);

  if (!userId || typeof userId !== 'string' || userId.length > 128) return { ok: false, error: 'Invalid userId' };
  if (!levelId || (typeof levelId !== 'string' && typeof levelId !== 'number')) return { ok: false, error: 'Invalid levelId' };

  if (score === null || score < 0 || score > 10_000_000) return { ok: false, error: 'Invalid score' };
  if (timeMs === null || timeMs < 0 || timeMs > 86_400_000) return { ok: false, error: 'Invalid timeMs' };

  const clientTs = body?.clientTs ? String(body.clientTs) : null;
  const deviceId = body?.deviceId ? String(body.deviceId).slice(0, 128) : null;
  const metadata = body?.metadata && typeof body.metadata === 'object' ? body.metadata : null;

  return {
    ok: true,
    value: {
      userId,
      levelId: String(levelId),
      score,
      timeMs,
      clientTs,
      deviceId,
      metadata
    }
  };
}

// -------------------- Endpoints --------------------

app.get('/health', (req, res) => {
  res.json({ ok: true, time: nowIso() });
});

// Complete a level: accepts client score and time, generates a pending reward.
app.post('/v1/levels/complete', (req, res) => {
  const v = validateCompletionPayload(req.body);
  if (!v.ok) return res.status(400).json({ ok: false, error: v.error });

  const { userId, levelId, score, timeMs, clientTs, deviceId, metadata } = v.value;

  const user = getOrCreateUser(userId);
  if (!user) return res.status(400).json({ ok: false, error: 'Invalid userId' });

  const prev = user.completedLevels.get(levelId) || null;
  const isFirstClear = !prev;

  // Store completion (keep best score and best time)
  const completion = {
    levelId,
    completedAt: nowIso(),
    clientTs,
    deviceId,
    metadata: metadata ? JSON.parse(JSON.stringify(metadata)) : null,
    attempts: (prev?.attempts || 0) + 1,
    bestScore: prev ? Math.max(prev.bestScore, score) : score,
    bestTimeMs: prev ? Math.min(prev.bestTimeMs, timeMs) : timeMs,
    lastScore: score,
    lastTimeMs: timeMs
  };
  user.completedLevels.set(levelId, completion);

  // Reward based on this completion (client metrics). If replay, still award but smaller.
  const baseReward = computeRewards({ levelId, score, timeMs, isFirstClear });
  const replayScale = isFirstClear ? 1.0 : 0.35;
  const reward = {
    rewardId: makeId('reward'),
    userId,
    levelId,
    createdAt: nowIso(),
    status: 'PENDING',
    reason: isFirstClear ? 'LEVEL_FIRST_CLEAR' : 'LEVEL_REPLAY',
    metrics: { score, timeMs },
    payout: {
      coins: clamp(Math.round(baseReward.coins * replayScale), 0, 500),
      gems: clamp(Math.round(baseReward.gems * replayScale), 0, 10)
    }
  };

  user.pendingRewards.set(reward.rewardId, reward);

  res.json({
    ok: true,
    completion: {
      levelId,
      attempts: completion.attempts,
      bestScore: completion.bestScore,
      bestTimeMs: completion.bestTimeMs,
      lastScore: completion.lastScore,
      lastTimeMs: completion.lastTimeMs
    },
    reward: {
      rewardId: reward.rewardId,
      status: reward.status,
      reason: reward.reason,
      payout: reward.payout
    },
    wallet: user.wallet
  });
});

// List pending rewards for a user.
app.get('/v1/rewards/pending', (req, res) => {
  const userId = req.query.userId ? String(req.query.userId) : null;
  if (!userId) return res.status(400).json({ ok: false, error: 'Missing userId' });

  const user = getOrCreateUser(userId);
  if (!user) return res.status(400).json({ ok: false, error: 'Invalid userId' });

  const pending = [];
  for (const r of user.pendingRewards.values()) {
    if (r.status === 'PENDING') pending.push(r);
  }

  res.json({ ok: true, userId, pending });
});

// Claim a reward: moves from pending to claimed and adds to wallet.
app.post('/v1/rewards/claim', (req, res) => {
  const userId = req.body?.userId ? String(req.body.userId) : null;
  const rewardId = req.body?.rewardId ? String(req.body.rewardId) : null;

  if (!userId || !rewardId) return res.status(400).json({ ok: false, error: 'Missing userId or rewardId' });

  const user = getOrCreateUser(userId);
  if (!user) return res.status(400).json({ ok: false, error: 'Invalid userId' });

  if (user.claimedRewards.has(rewardId)) {
    return res.json({ ok: true, status: 'ALREADY_CLAIMED', wallet: user.wallet });
  }

  const reward = user.pendingRewards.get(rewardId);
  if (!reward) return res.status(404).json({ ok: false, error: 'Reward not found' });
  if (reward.userId !== userId) return res.status(403).json({ ok: false, error: 'Reward does not belong to user' });
  if (reward.status !== 'PENDING') return res.status(409).json({ ok: false, error: 'Reward not claimable' });

  // Apply payout
  const coins = clamp(parseIntSafe(reward.payout?.coins) ?? 0, 0, 1_000_000_000);
  const gems = clamp(parseIntSafe(reward.payout?.gems) ?? 0, 0, 1_000_000_000);

  user.wallet.coins += coins;
  user.wallet.gems += gems;

  reward.status = 'CLAIMED';
  reward.claimedAt = nowIso();

  user.pendingRewards.set(rewardId, reward);
  user.claimedRewards.add(rewardId);

  res.json({
    ok: true,
    status: 'CLAIMED',
    reward: {
      rewardId: reward.rewardId,
      levelId: reward.levelId,
      reason: reward.reason,
      payout: reward.payout,
      createdAt: reward.createdAt,
      claimedAt: reward.claimedAt
    },
    wallet: user.wallet
  });
});

// Optional: get user state
app.get('/v1/users/:userId', (req, res) => {
  const userId = String(req.params.userId || '');
  const user = getOrCreateUser(userId);
  if (!user) return res.status(400).json({ ok: false, error: 'Invalid userId' });

  const completedLevels = {};
  for (const [levelId, completion] of user.completedLevels.entries()) completedLevels[levelId] = completion;

  const pending = [];
  for (const r of user.pendingRewards.values()) if (r.status === 'PENDING') pending.push(r);

  res.json({
    ok: true,
    user: {
      userId: user.userId,
      createdAt: user.createdAt,
      wallet: user.wallet,
      completedLevels,
      pendingRewards: pending
    }
  });
});

// -------------------- Start --------------------
app.listen(PORT, () => {
  console.log(`Game API listening on port ${PORT}`);
});